// Validar si la fecha es pasada
const fechaTexto = $input.first().json.Fecha;
const fechaInput = new Date(fechaTexto);
const fechaActual = new Date();

// Resetear horas para comparar solo fechas
fechaActual.setHours(0, 0, 0, 0);
fechaInput.setHours(0, 0, 0, 0);

if (fechaInput < fechaActual) {
  return [{
    json: {
      valida: false,
      resultado: "La fecha ingresada es pasada, por favor ingrese una fecha válida",
      fecha: fechaTexto
    }
  }];
}

// Si la fecha es válida, procesamos
const fechaOriginal = new Date($input.first().json.Fecha);

// Formatear fecha y extraer componentes
const dd = String(fechaOriginal.getDate()).padStart(2, '0');
const mm = String(fechaOriginal.getMonth() + 1).padStart(2, '0');
const yyyy = fechaOriginal.getFullYear();
const HH = String(fechaOriginal.getHours()).padStart(2, '0');
const min = String(fechaOriginal.getMinutes()).padStart(2, '0');

// Obtener día de la semana
const diasSemana = ["domingo", "lunes", "martes", "miércoles", "jueves", "viernes", "sábado"];
const diaSemana = diasSemana[fechaOriginal.getDay()];

return [{
  json: {
    valida: true,
    fechaFormateada: `${dd}/${mm}/${yyyy} ${HH}:${min}`,
    hora: `${HH}:${min}`,
    diaSemana: diaSemana,
    fechaOriginal: fechaTexto
  }
}];

// Entrada: se espera que venga un campo fecha_solicitada y los horarios por día
const item = $json;

// Obtener fecha solicitada
const fechaSolicitada = new Date(item.fecha_solicitada);
if (isNaN(fechaSolicitada.getTime())) {
  throw new Error("La fecha solicitada no es válida");
}

// Mapear días en español
const diasSemana = [
  "Domingo", "Lunes", "Martes", "Miercoles", "Jueves", "Viernes", "Sabado"
];

const diaSemana = diasSemana[fechaSolicitada.getDay()]; // ej: "Lunes"
const horaSolicitada = fechaSolicitada.getHours() + fechaSolicitada.getMinutes() / 60;

// Obtener horario del día correspondiente
let horarioDelDia = item[diaSemana];
let estaAbierto = false;
let mensaje = "";

// Si no hay horario configurado para ese día
if (!horarioDelDia || horarioDelDia.toLowerCase().includes("cerrado")) {
  mensaje = `El ${diaSemana} está cerrado.`;
} else {
  // Extraer rango de horario "De 9:30 hs a 18:30 hs"
  const match = horarioDelDia.match(/De (\d{1,2}):(\d{2}) hs a (\d{1,2}):(\d{2}) hs/);

  if (match) {
    const horaInicio = parseInt(match[1]) + parseInt(match[2]) / 60;
    const horaFin = parseInt(match[3]) + parseInt(match[4]) / 60;

    if (horaSolicitada >= horaInicio && horaSolicitada <= horaFin) {
      estaAbierto = true;
      mensaje = `El ${diaSemana} a las ${fechaSolicitada.toLocaleTimeString("es-AR", {hour: '2-digit', minute:'2-digit'})} está disponible.`;
    } else {
      mensaje = `El ${diaSemana} está fuera de horario (${horarioDelDia}).`;
    }
  } else {
    mensaje = `No se pudo interpretar el horario para ${diaSemana}.`;
  }
}

// Salida para n8n
return [{
  json: {
    diaConsultado: diaSemana,
    fechaSolicitada: fechaSolicitada.toISOString(),
    horaConsultada: fechaSolicitada.toLocaleTimeString("es-AR", {hour: '2-digit', minute:'2-digit'}),
    horarioDelDia,
    estaAbierto,
    mensaje
  }
}];

